oilerplate_gt_06": 0.0}, "diversity_bm25_count": 0, "supporting_doc_types": ["faq", "conversation"], "supporting_bm25_count": 19, "intent_fetch_doc_types": ["policy", "tos", "faq", "howto"], "authoritative_doc_types": ["policy", "tos", "howto"], "supporting_vector_count": 20, "diversity_doc_types_covered": ["faq"]}, "evidence_summary": [{"score": 0.030886196246139225, "snippet": "### 知识条目：RETURN-001\\n适用场景：七天无理由退货\\n用户问法：衣服不喜欢可以退吗？\\n标准答复：您好，符合条件的网络购物商品通常可在签收后七日内申请无理由退货。退回商品需保持完好，不影响二次销售，吊牌、配件、赠品、包装等尽量齐全。具体是否支持退货请以商品详情页、订单页和平台规则为准。\\n检索关键词：七天无理由，不喜欢退货，退货条件，吊牌，二次销售\\n转人工条件：商品已穿着、洗涤、污损、吊牌缺失或争议较大。...", "chunk_id": "8407742d-6db5-4e3e-851e-cab94de883ba", "doc_type": "faq", "source_url": "file://a30c7a8b-08_退换货规则与流程.md"}, {"score": 0.030834914611005692, "snippet": "### 知识条目：RETURN-002\\n适用场景：换货流程\\n用户问法：尺码不合适怎么换？\\n标准答复：您好，尺码不合适可以在售后期内申请换货。请在订单售后入口选择“换货”，填写需要更换的颜色或尺码，并按页面提示寄回商品。仓库收到并验收通过后，会尽快为您寄出换货商品。若换货尺码无库存，可选择退货退款。\\n检索关键词：换货，尺码不合适，换颜色，售后入口，寄回\\n转人工条件：换货商品缺货、用户需要加急发出、跨款换货。...", "chunk_id": "2e86643d-9b7b-4ab2-ac02-b240ed731206", "doc_type": "faq", "source_url": "file://a30c7a8b-08_退换货规则与流程.md"}, {"score": 0.029513888888888888, "snippet": "### 知识条目：RETURN-004\\n适用场景：不可退换情形\\n用户问法：吊牌剪了还能退吗？洗过还能退吗？\\n标准答复：您好，若商品吊牌缺失、已洗涤、明显穿着、沾染香水/化妆品/污渍，或影响二次销售，通常可能无法支持无理由退换。若是商品本身质量问题，请提供照片或视频，我们会根据实际情况核实处理。\\n检索关键词：吊牌剪了，洗过，穿过，污渍，影响二次销售，不可退\\n转人工条件：用户坚持退货、存在质量争议或平台介入。...", "chunk_id": "c4f2acc2-746b-4860-94c3-af8fc6776e56", "doc_type": "faq", "source_url": "file://a30c7a8b-08_退换货规则与流程.md"}, {"score": 0.029206349206349208, "snippet": "### 知识条目：RETURN-003\\n适用场景：质量问题退换\\n用户问法：衣服有破洞/开线/污渍怎么办？\\n标准答复：非常抱歉给您带来不好的体验。请您提供商品问题位置照片、整体照片、吊牌照片和订单号，我们会尽快核实。若确认为质量问题，将按平台和店铺规则为您办理退换货或其他售后方案。\\n检索关键词：质量问题，破洞，开线，污渍，瑕疵，售后\\n转人工条件：用户要求赔偿、质检争议、已穿洗后发现问题。", "chunk_id": "223e1789-f643-4ec7-a67c-d36fbf361fa1", "doc_type": "faq", "source_url": "file://a30c7a8b-08_退换货规则与流程.md"}, {"score": 0.02854251012145749, "snippet": "### 知识条目：RETURN-005\\n适用场景：退货运费\\n用户问法：退货运费谁承担？\\n标准答复：您好，因尺码不合适、不喜欢、拍错等个人原因退货，运费通常按平台规则或订单权益承担；若确认为商品质量问题、错发、漏发，通常由商家承担合理运费。请先在售后页面查看是否有运费险或平台补贴。\\n检索关键词：退货运费，运费险，谁承担，质量问题，个人原因\\n转人工条件：运费险理赔失败、超额运费报销争议。", "chunk_id": "241ad6c1-6db1-4b1b-98da-d62ba07c11b4", "doc_type": "faq", "source_url": "file://a30c7a8b-08_退换货规则与流程.md"}, {"score": 0.026333907056798625, "snippet": "### 知识条目：REFUND-001\\n适用场景：退款时效\\n用户问法：退货寄回了，什么时候退款？\\n标准答复：您好，退货包裹到仓后需要进行验收，确认商品符合退货条件后会发起退款。退款通常原路退回至您的支付账户，到账时间受支付渠道影响。您可以在订单售后详情页查看当前进度。\\n检索关键词：退款，到账，退货验收，原路退回，售后进度\\n转人工条件：仓库签收超过承诺时间仍未退款。", "chunk_id": "28cbf4db-dbe2-4f25-a842-d2750fcccd96", "doc_type": "faq", "source_url": "file://152f1716-09_退款到账与售后进度.txt"}, {"score": 0.026171741361614778, "snippet": "### 知识条目：REFUND-003\\n适用场景：售后申请被拒\\n用户问法：我的退货为什么被拒绝？\\n标准答复：您好，售后被拒可能是因为超出售后期、商品影响二次销售、缺少必要凭证、申请原因与实际不符等。您可以查看售后详情中的拒绝原因；若您认为判断有误，请补充照片、视频或物流凭证，我们会再次核实。\\n检索关键词：售后被拒，退货拒绝，退款失败，补充凭证，二次销售\\n转人工条件：用户申请平台介入或投诉升级。", "chunk_id": "c2857aeb-9633-4ad2-a596-f34284a924c1", "doc_type": "faq", "source_url": "file://152f1716-09_退款到账与售后进度.txt"}, {"score": 0.02571241401899771, "snippet": "### 知识条目：SPEC-001\\n适用场景：内衣 / 贴身衣物\\n用户问法：内衣可以七天无理由退货吗？\\n标准答复：您好，内衣、袜子、打底裤、塑身衣等贴身类商品因卫生和安全原因，是否支持无理由退货需以商品详情页和平台规则为准。若商品已拆封、试穿、洗涤或影响二次销售，通常可能无法退换。质量问题可提供照片核实。\\n检索关键词：内衣，贴身衣物，袜子，打底裤，卫生，不支持退货\\n转人工条件：商品页面规则不清晰或用户主张质量问题。...", "chunk_id": "379764d3-f0d1-4d25-8e39-85627164f21c", "doc_type": "faq", "source_url": "file://5cb7d15f-11_特殊品类规则.txt"}, {"score": 0.025657894736842105, "snippet": "### 知识条目：ERR-003\\n适用场景：运输破损\\n用户问法：收到包裹破了，衣服也脏了怎么办？\\n标准答复：非常抱歉。请您保留外包装、面单和商品现状，并拍摄清晰照片或视频。我们会根据破损情况联系快递核实，并为您提供换货、退货或补偿方案。\\n检索关键词：包裹破损，运输破损，衣服脏了，快递，外包装\\n转人工条件：商品无法使用、用户拒收、快递责任认定争议。", "chunk_id": "e800a0bb-e302-4161-933a-1f7f27354e44", "doc_type": "faq", "source_url": "file://c84a670b-12_发错漏发破损处理.txt"}], "followup_questions": [], "llm_usage_breakdown": [{"input": 1471, "model": "mimo-v2.5", "output": 490, "cost_usd": 0.001471}, {"input": 3217, "model": "mimo-v2.5", "output": 562, "cost_usd": 0.002451}, {"input": 2281, "model": "mimo-v2.5", "output": 94, "cost_usd": 0.001282}, {"input":