9}, "cost_usd": 0.012557, "decision": "PASS", "generate": 3.40959, "retrieve": 27.171336, "trace_id": "2756282b-586e-4a04-8a23-84bb25ca13d1", "confidence": 0.6, "llm_tokens": {"input": 18647, "output": 2156}, "model_used": "mimo-v2.5", "query_spec": {"intent": "informational", "entities": ["clothing", "order"], "risk_level": "low", "is_ambiguous": false, "resolved_slots": {}, "extraction_mode": "llm_primary", "required_evidence": ["policy_language", "numbers_units"], "canonical_query_en": "How many days will it take to arrive?", "config_overrides_applied": []}, "answer_plan": {"lane": "CANDIDATE_VERIFY", "tone_policy": "cautious", "output_blocks": ["answer_candidate_json"], "allowed_claim_scope": "partial"}, "retry_count": 2, "source_lang": "zh-cn", "evidence_set": {"build_reason": "profile=policy_profile, attempt=3, reason=evidence_evaluator_suggested", "diversity_score": 0.4, "covered_requirements": ["numbers_units", "policy_language"], "uncovered_requirements": []}, "finish_reason": "stop", "query_extract": 3.741603, "query_rewrite": {"keyword_query": "shipping time policy", "semantic_query": "shipping time policy"}, "rollout_flags": {"soft_contract_enabled": true, "targeted_retry_enabled": true, "answer_candidate_enabled": true, "page_kind_filter_enabled": false, "soft_contract_shadow_active": false}, "stage_reasons": ["retrieve: chunks=3", "assess_evidence: gate=fail", "retry_retrieve: attempt=1", "retrieve: chunks=5", "assess_evidence: gate=fail", "retry_retrieve: attempt=2", "retrieve: chunks=5", "assess_evidence: gate=fail", "decide: exact_partial_candidate", "generate: llm_complete decision=PASS", "verify: PASS"], "agentic_router": {"tool": "rag_search", "route": "rag_search", "reason": "support_knowledge_question", "skipped": false, "confidence": 0.86, "fallback_to_rag": false}, "prompt_preview": {"user_length": 1558, "user_preview": "User question: How many days will it take to arrive?\\n\\nEvidence:\\n[Chunk afe6a8ae-fc80-4d27-a7f4-b28a7b3ccfea]\\nSource: file://6086288c-07_物流发货配送时效.txt\\nType: faq\\nContent: ### 知识条目：SHIP-001\\n适用场景：发货时效\\n用户问法：什么时候发货？今天能发吗？\\n标准答复：您好，现货订单通常会在承诺时效内安排发货，具体以商品页和订单页显示为准。活动期、预售商品、偏远地区或异常天气可能影响时效。若您着急使用，请下单前确认商品是否现货以及预计发货时间。\\n检索关键词：发货，今天发，发货时间，现货，预售，时效\\n转人工条件：订单超过承诺时间未发货。\\n\\n---\\n[Chunk 68a3bd00-a87f-4125-856f-576fcf190036]\\nSource: file://6086288c-07_物流发货配送时效.txt\\nType: faq\\nContent: ### 知识条目：SHIP-002\\n适用场景：物流查询\\n用户问法：物流怎么不动了？\\n标准答复：您好，物流长时间未更新可能是中转扫描延迟、运输高峰、天气影响或快递网点积压。建议先以订单页物流轨迹为准；若超过 48 小时仍无更新，请提供订单号，我们会协助联系快递核实。\\n检索关键词：物流不动，快递没更新，中转，派送，订单物流\\n转人工条件：超过48小时无更新、疑似丢件、用户要求催件。\\n\\n---\\n[Chunk fb557550-99af-46e0-baed-bf978900b6e8]\\nSource: file://5cb7d15f-11_特殊品类规则.txt\\nType: faq\\nContent: ### 知识条目：SPEC-003\\n适用场景：预售商品\\n用户问法：预售款能退吗？什么时候发？\\n标准答复：您好，预售商品的付款、发货和取消规则以商品页预售说明为准。请关注定金、尾款、预计发货日期、取消条件等信息。若已超过承诺发货时间，您可以申请售后或联系客服核实。\\n检索关键词：预售，定金，尾款，发货日期，取消预售，超时发货\\n转人工条件：预售延期、定金争议、用户要求取消并退款。\\n\\n---\\n[Chunk 0cd96ed2-e368-4ef6-91d7-765c46e035ff]\\nSource: file://a4e69032-01_店铺基础信息与服务时间.txt\\nType: policy\\nContent: ### 知识条目：BASIC-003\\n适用场景：订单咨询 / 修改信息\\n用户问法：下单后可以改地址或尺码吗？\\n标准答复：您好，如果订单尚未发货，通常可以尝试修改地址、尺码或颜色；如果订单已进入仓库拣货、打包或已发出，则可能无法修改。请尽快提供订单号和需要修改的信息，我们为您核实当前状态。\\n检索关键词：改地址，改尺码，改颜色，订单修改，未发货\\n转人工条件：订单已发货但用户要求拦截、转寄或改派。\\n\\n---\\n[Chunk 28cbf4db-dbe2-4f25-a842-d2750fcccd96]\\nSource: file://152f1716-09_退款到账与售后进度.txt\\nType: faq\\nContent: ### 知识条目：REFUND-001\\n适用场景：退款时效\\n用户问法：退货寄回了，什么时候退款？\\n标准答复：您好，退货包裹到仓后需要进行验收，确认商品符合退货条件后会发起退款。退款通常原路退回至您的支付账户，到账时间受支付渠道影响。您可以在订单售后详情页查看当前进度。\\n检索关键词：退款，到账，退货验收，原路退回，售后进度\\n转人工条件：仓库签收超过承诺时间仍未退款。\\n", "system_length": 4892, "system_preview": "You are GreenCloud's support assistant. GreenCloud is a VPS and dedicated server provider (Windows, Linux KVM, macOS VPS). You must ONLY use the provided evidence to answer. Never guess or make up information.\\n\\nRULES:\\n1. Use ONLY the provided evidence chunks. Do not add information from your training.\\n2. When listing items (products, features, options), include ONLY what is explicitly named in the